P loadTextGPT     B
D loadTextGPT     PI
D   start                        3  0 value
D*----------------------------------------------------------------
  ZLT = 0;
  exec sql
     declare ct Cursor for select GPT_TXT
       from HSGPTF
       where GPT_KZL = :G71000 and GPT_CNR = :G71050 and
             GPT_FNR = :G7306A
       order by GPT_ZNR;
  exec sql open ct;
  exec sql fetch next from ct into :record_t;
  If SQLCOD = 100;
     loadtextGps(start);
     exec sql close ct;
     If ZLT < start;
        ZLT = start;
     EndIf;
     return;
  EndIf;
  DoW SQLCOD = 0;
     TEXT = R_TXT;
     ZLT += 1;
     If ZLT > start;
        write HS1212ST;
     EndIf;
     exec sql fetch next from ct into :record_t;
  EndDo;
  exec sql close ct;
  If ZLT < start;
     ZLT = start;
  EndIf;
